"""
verify kelem against TACS GPU / CPU code for MITC shell in local python
* we only have the MITC shell again in local python in order to help more easily debug + see tying strains / stresses for interp and study of the cohomology

* other test script for TACS GPU located in tests/elements/shell_jac.cu and associated includes (TACS CPU in tests/elements/baseline/jac-tacs.cpp)
"""

import numpy as np

# random xpts
xpts = np.zeros(12)
for ixpt in range(12):
    xpts[ixpt] = 1.0345452 + 2.23123432 * ixpt + 0.323 * ixpt * ixpt

E = 70e9; nu = 0.33; t = 0.005


import numpy as np
import sys
sys.path.append("src/")
from elem import MITCShellElement
    
strain_debug_mode = 'all' # strain components
# strain_debug_mode = 'drill' # strain components
# strain_debug_mode = 'tying' # strain components
# strain_debug_mode = 'bending' # strain components


ELEMENT = MITCShellElement(strain_debug_mode=strain_debug_mode)

# assemble only one element (geometric linear)
loc_kelem = ELEMENT.get_kelem(E, nu, t, xpts)


